INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('uber-eats', 'Uber Eats', 'food-delivery', 51, 'NOGO', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.ubereats.com&size=128', 'https://www.ubereats.com', $json$[{"category":"Compliance","score":"16/20","description":"No major fines/bans. Subject to CompCom scrutiny (2023: lower fees ordered, pledged R200m investment). Operational in competitive market; driver protests but no shutdowns."},{"category":"Customer Satisfaction","score":"5/20","description":"HelloPeter 1.5/10 (1,511 reviews), overwhelmingly negative on delivery/no-shows/refunds. App ratings high globally but SA-specific complaints align."},{"category":"Product Value","score":"18/30","description":"Wide range but high markups (20-45% vs in-store), fees erode value; convenience premium."},{"category":"Innovation","score":"8/10","description":"Real-time tracking, Uber One sub, grocery/dark stores, SPAR partnership (275+ stores), safety tech (hour limits, emergency)."},{"category":"Customer Support","score":"4/15","description":"App chat/Help center primary; reviews cite unresponsive, no phone for customers, poor resolution."},{"category":"Accessibility & Security","score":"8/10","description":"App accessible on iOS/Android; no specific inclusivity issues found. No recent SA data breaches or POPIA violations reported. Global safety features like emergency button implemented."}]$json$::jsonb, $json$["real-time tracking","Uber One","grocery delivery","wide restaurant range","pickup","promotions"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Delivery R20+, 20-45% menu markup, Uber One R50/mo (R0 deliv >R100)","features":""}]$json$::jsonb, $json${"google_play":"4.6","ios":"4.7"}$json$::jsonb, $json$["convenience","variety","app usability","economic scale"]$json$::jsonb, $json$["delivery issues","high markups","refund failures"]$json$::jsonb, $json${"summary":"Strongly negative on HelloPeter/Google (delivery/refund fails); app ratings contradict but review themes poor.","positive_themes":["variety","promotions","fast when works"],"common_concerns":["delivery failures","no refunds","high prices","poor support"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('tsu-protection-services', 'TSU Protection Services', 'armed-response', 74, 'GO WITH CAUTION', 'https://tsuafrica.com/wp-content/uploads/2021/03/cropped-TSU-Protection-Services-Logo-07-500x504.png', 'https://www.tsu.co.za', $json$[{"category":"Compliance","score":"18/20","description":"PSiRA accredited per job postings and training; site commits to statutory compliance; no violations found"},{"category":"Customer Satisfaction","score":"10/20","description":"No HelloPeter or Google customer reviews found (0 ratings); high employee satisfaction 4.5/5 on Indeed"},{"category":"Product Value","score":"25/30","description":"Full service range at likely competitive rates; lacks pricing transparency"},{"category":"Innovation","score":"7/10","description":"TSU Protect app (panic/shake alert, stealth mode, video streaming, man-down, journey tracking, geofence); IoT trackers, smart gate control"},{"category":"Customer Support","score":"10/12","description":"monitoring/control room; app linked to rapid response network"},{"category":"Accessibility & Security","score":"8/10","description":"App provides digital access; claims POPI/GDPR compliance; PSiRA standards ensure security practices"}]$json$::jsonb, $json$["armed response","tactical units","executive protection","24/7 monitoring","riot control","TSU Protect app"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Industry avg R400-1000/mo (no specific pricing published)","features":""}]$json$::jsonb, $json${"google_play":"N/A (5K+ downloads)","ios":"N/A"}$json$::jsonb, $json$["PSiRA accredited","ex-SAPS expertise","strong employee ratings","corporate reputation"]$json$::jsonb, $json$["scarce customer reviews","no public pricing","low app adoption"]$json$::jsonb, $json${"summary":"Positive employee feedback; active hiring/recruitment posts; no customer complaints or negative news","positive_themes":["professional training","reliable armed response","career growth"],"common_concerns":["long hours for staff","limited customer feedback"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('securitas-south-africa', 'Securitas South Africa', 'armed-response', 72, 'GO WITH CAUTION', 'https://cdn.theorg.com/9e0591bd-0d2a-49b9-8320-dcc5358b4b7b_small.jpg', 'https://www.securitas.co.za', $json$[{"category":"Compliance","score":"18/20","description":"PSIRA registered as major operator (inferred from operations/training); no 2025/2026 violations found; claims full regulatory compliance."},{"category":"Customer Satisfaction","score":"10/20","description":"Limited SA-specific reviews found (HelloPeter page exists but sparse); global Securitas employee reviews mixed ~3/5; no strong negative consumer patterns in SA."},{"category":"Product Value","score":"25/30","description":"Competitive industry pricing assumed; comprehensive services but lacks transparent quotes."},{"category":"Innovation","score":"7/10","description":"Remote guarding, electronic security, SOC tech integration, mobile patrols with tech; global MySecuritas app (3.7/5 Android)."},{"category":"Customer Support","score":"9/12","description":"Contact form, phone (+27 86 110 0900), SOC 24/7; global feedback indicates delays but SA site emphasizes operations centers."},{"category":"Accessibility & Security","score":"7/10","description":"Global brand with website and contact form; no specific POPIA mentions found but claims compliance with laws. MySecuritas app available for management."}]$json$::jsonb, $json$["Mobile guarding/alarm response","remote video surveillance","manned guarding","electronic security","SOC monitoring","risk management"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Not publicly listed; industry armed response ~R400-1000/mo ZAR; SME fixed monthly fees","features":""}]$json$::jsonb, $json${"google_play":"N/A (no SA-specific app)","ios":"N/A (no SA-specific app)"}$json$::jsonb, $json$["Global leader (3800+ SA employees)","PSIRA training centers","integrated tech+guarding","tailored SME solutions"]$json$::jsonb, $json$["sparse local reviews","unclear armed response branding","pricing not public"]$json$::jsonb, $json${"summary":"No recent SA-specific negative news; global mixed employee feedback; limited consumer visibility.","positive_themes":["reliable operations","tech adoption","large scale presence"],"common_concerns":["limited customer reviews","no specific SA ratings data","global complaints on support"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('chubb-armed-response', 'Chubb Armed Response', 'armed-response', 74, 'GO WITH CAUTION', 'https://media.licdn.com/dms/image/v2/C560BAQFJTEV_mrcDwQ/company-logo_200_200/company-logo_200_200/0/1631347446412', 'https://www.chubb.co.za', $json$[{"category":"Compliance","score":"17/20","description":"Historical PSIRA registration and ISO 9001. No recent violations found. Rebrand to 100% SA-owned complies with local laws. Chubb Insurance B-BBEE certified to 2026."},{"category":"Customer Satisfaction","score":"16/20","description":"Mixed HelloPeter complaints on response (1hr delays), billing. Indeed 3.2/5 (626 reviews). National Security 3.0/5."},{"category":"Product Value","score":"24/30","description":"Standard industry packages; value questioned in reviews due to response issues vs price. Transparent historical but no current site."},{"category":"Innovation","score":"5/10","description":"SMS alerts, CCTV integration, cloud monitoring (global apps). No standout SA digital innovation 2025. ChubbView app 4/5 iOS."},{"category":"Customer Support","score":"9/15","description":"Monitoring promised, but reviews cite slow response, unprofessional dispatch. Channels: phone, control room."},{"category":"Accessibility & Security","score":"7/10","description":"Global Chubb sites mention encryption, firewalls, POPIA-equivalent privacy policies, employee training. No SA-specific POPIA issues found."}]$json$::jsonb, $json$["24/7 alarm monitoring","armed response","electronic security","CCTV","fire protection","PSIRA-trained officers","national dispatch"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Industry avg R700/mo (R400-1000)","features":""}]$json$::jsonb, $json${"google_play":"N/A (global Chubb app low downloads)","ios":"4.0/5 (ChubbView, 5 ratings)"}$json$::jsonb, $json$["national footprint","integrated fire/security","rigorous training","ISO accredited"]$json$::jsonb, $json$["slow armed response","billing after cancellation","service post-rebrand"]$json$::jsonb, $json${"summary":"Legacy positive on footprint; recent reviews mixed-negative on service. Rebrand 2018. Employee feedback average.","positive_themes":["professional training","national coverage","reliable monitoring"],"common_concerns":["slow response times","billing disputes","poor management"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('excellerate-services', 'Excellerate Services', 'armed-response', 65, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.excellerate.co.za&size=128', 'https://www.excellerate.co.za', $json$[{"category":"Compliance","score":"17/20","description":"PSIRA registered officers (Grade C required), SAIDSA-aligned, published POPIA manual, no major violations found, opposed restrictive 2025 PSIRA amendments."},{"category":"Customer Satisfaction","score":"8/20","description":"Few HelloPeter reviews (4 total, mostly 1-star on rude guards 2021), Indeed employee rating 3.1/5 (pay/management complaints), no recent Google customer ratings found. Low volume negative."},{"category":"Product Value","score":"20/30","description":"Competitive industry pricing assumed for large provider; comprehensive packages with unlimited callouts/monitoring. No direct value complaints."},{"category":"Innovation","score":"6/10","description":"Smart technology, AI surveillance mentioned in blogs, tactical units; no dedicated customer app."},{"category":"Customer Support","score":"9/15","description":"Control rooms, dedicated managers, regional support; reviews cite poor attitude/response quality."},{"category":"Accessibility & Security","score":"8/10","description":"POPIA manual published with detailed security measures including access control, data memory control, transmission control. Website accessible."}]$json$::jsonb, $json$["armed/tactical response","manned guarding","remote monitoring","24/7 control rooms","5800 officers","246 vehicles"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Industry avg R400-1000/mo (R700)","features":""}]$json$::jsonb, $json${"google_play":"N/A","ios":"N/A"}$json$::jsonb, $json$["national scale (1200 sites)","PSIRA/SAIDSA compliant","POPIA compliant","advanced control rooms/tech"]$json$::jsonb, $json$["rude/unprofessional staff","negative employee sentiment","limited recent customer reviews"]$json$::jsonb, $json${"summary":"Mixed employee reviews (3.1/5 Indeed), sparse negative customer feedback on HelloPeter; company promotes positive incidents/responses.","positive_themes":["reliable scale","fast response","technology adoption"],"common_concerns":["rude guards","poor service attitude","payment/management issues"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('stallion-integrated-security', 'STALLion Integrated Security', 'armed-response', 69, 'GO WITH CAUTION', 'https://www.stallion.co.za/wp-content/uploads/2025/03/Stallion-Integrated-Logo-RGB_FC-Horizontal-Black.png', 'https://www.stallion.co.za', $json$[{"category":"Compliance","score":"18/20","description":"PSIRA accredited training center, requires PSIRA for staff, B-BBEE Level 1, no negative regulatory issues found."},{"category":"Customer Satisfaction","score":"10/20","description":"HelloPeter 3/5 from 5 recent 1-star reviews on service failures; employee Indeed 4/5; limited customer Google data."},{"category":"Product Value","score":"25/30","description":"Standard industry pricing for comprehensive armed response, guarding, tech; good range but value questioned by poor service reviews."},{"category":"Innovation","score":"7/10","description":"Technology solutions, integrated tech+manpower, CCTV on vehicles, cloud VMS app (possibly related), learnerships."},{"category":"Customer Support","score":"6/15","description":"Reviews highlight poor on-site support, unresponsive guards, admin delays in payouts/placements."},{"category":"Accessibility & Security","score":"6/10","description":"Website accessible, tech solutions mentioned but no specific POPIA mention or app for customers; assumes standard security practices."}]$json$::jsonb, $json$["armed response units","guarding with 7500 officers","specialised ops (riot/VIP)","tech integration","training center","nationwide coverage"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: R400-R1000/mo typical for Gauteng armed response (industry avg 2025)","features":""}]$json$::jsonb, $json${"google_play":"N/A (no customer app found)","ios":"N/A (no customer app found)"}$json$::jsonb, $json$["established 30+ years","large scale deployment","PSIRA accredited","specialised high-risk services","B-BBEE Level 1"]$json$::jsonb, $json$["poor service response","rude staff","ineffective theft prevention"]$json$::jsonb, $json${"summary":"HelloPeter poor (3/5, all recent negative); Indeed employee positive (4/5); limited other social/customer data.","positive_themes":["professional training","large workforce","specialised capabilities"],"common_concerns":["arrogant guards","poor response","admin delays","theft despite security"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('fidelity-adt', 'Fidelity ADT', 'armed-response', 71, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.fidelity-adt.co.za&size=128', 'https://www.fidelity-adt.co.za', $json$[{"category":"Compliance","score":"18/20","description":"PSIRA registered Reg#765528 since 2001, certificate valid (shown on site despite old date). Competition Commission approvals for 2025 acquisitions. No major regulatory issues found."},{"category":"Customer Satisfaction","score":"8/20","description":"HelloPeter ADT Security 2.8/5, Fidelity Security 2.3/5. Negative forum sentiments on service/response. Employee reviews 3.5/5 Indeed. Low satisfaction."},{"category":"Product Value","score":"25/30","description":"Comprehensive range, competitive pricing vs market, but value questioned in poor reviews. Transparent via site/partners."},{"category":"Innovation","score":"8/10","description":"SecureHome app for arm/disarm/CCTV/notifications, FindU panic app (R49/m), VumaCam partnership (18k cams), SecureFire launch June 2025. Tech adoption good."},{"category":"Customer Support","score":"8/15","description":"Lines (0861 212 300), but reviews cite slow/ineffective support, billing hassles."},{"category":"Accessibility & Security","score":"8/10","description":"Apps available for remote access (SecureHome, FindU), no data collection per privacy policy, no POPIA violations found. Digital access good but app bugs noted."}]$json$::jsonb, $json$["24hr armed response","CCTV monitoring","app remote control","electric fencing","VumaCam LPR","medical assist","SecureFire"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Armed response from ~R400-R1000/mo (market avg R700), partner ex R364/mo","features":""}]$json$::jsonb, $json${"google_play":"N/A (FidelitySecure low downloads, no rating shown)","ios":"~4/5 (limited reviews)"}$json$::jsonb, $json$["PSIRA compliant","largest SA provider (>5000 officers)","national coverage","BEE1","recent expansions/awards"]$json$::jsonb, $json$["slow response","billing issues","poor service resolution"]$json$::jsonb, $json${"summary":"Mixed-negative customer reviews on forums/HelloPeter (response/service), positive news on expansions.","positive_themes":["large reliable company","tech features","quick growth"],"common_concerns":["slow response times","poor customer service","billing/cancellation issues"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('thorburn-security-solutions', 'Thorburn Security Solutions', 'armed-response', 62, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.thorburn.co.za&size=128', 'https://www.thorburn.co.za', $json$[{"category":"Compliance","score":"18/20","description":"Claims full PSIRA compliance, SASA Gold, ISO certified, SAIDSA, SASSETA, Level 1 B-BBEE, no violations found."},{"category":"Customer Satisfaction","score":"4/10","description":"HelloPeter 2.6/5 (1 recent 1-star: no armed response); Indeed employees 4/5 (92 reviews). Limited customer data."},{"category":"Product Value","score":"20/30","description":"Wide range incl armed reaction, monitoring, facilities mgmt. Value unclear sans pricing."},{"category":"Innovation","score":"7/10","description":"AI cameras, IoT, thermal/facial rec, CiiMS, Guard Tower solar CCTV. No app."},{"category":"Customer Support","score":"8/12","description":"Command centre; complaint of delayed response. Employee reviews note client comms. Phone/email support."},{"category":"Accessibility & Security","score":"8/10","description":"Nationwide coverage, website accessible, POPIA compliant policy with data subject forms. Digital dashboards. No app limits some access."}]$json$::jsonb, $json$["24/7 monitoring & armed response","AI/IoT surveillance","manned guarding","facilities management","Guard Tower solar CCTV","CiiMS platform"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Not publicly listed; industry avg R700/mo armed response ZAR","features":""}]$json$::jsonb, $json${"google_play":"N/A (no consumer app)","ios":"N/A (no consumer app)"}$json$::jsonb, $json$["multiple certifications","AI/IoT tech","B-BBEE Level 1","national scale (10k officers)","POPIA compliant"]$json$::jsonb, $json$["one recent no-response complaint","no consumer app","pricing opacity"]$json$::jsonb, $json${"summary":"Sparse reviews; positive on LinkedIn, Indeed employees positive (4/5); HelloPeter critical.","positive_themes":["AI tech adoption","reliable guarding","professional staff"],"common_concerns":["delayed armed response","limited consumer visibility"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
